var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오즈를 놓쳤어…… 우리 힘으로는 못 잡아…….","JPN":"オズを逃した……私たちの力では捕まえられない……","ENG":"We lost OZ... We can’t catch them on our own...","TWN":"沒抓到奧茲國……光憑我們根本沒辦法……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그럼 우리 벌받는 거야?","JPN":"じゃ、じゃあ、私たちお仕置きされる？","ENG":"Th-then... Are we getting punished?","TWN":"那…我們會被懲罰嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"벌받고 싶지 않아. 다시 오즈를 붙잡자.","JPN":"お仕置きされたくない。もう一回オズを捕まえよう。","ENG":"I don’t want to get punished. Let’s capture OZ.","TWN":"我不想受罰，再去抓她們吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"헤론…… 헤론 님이 안 계셔.","JPN":"ヘロン……ヘロン様がいない。","ENG":"Madam... Madam Heron isn’t here.","TWN":"可是……海倫夫人不在。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"헤론 님이 가시면 우린 악몽을 꾸게 될 거야…….","JPN":"ヘロン様がいないと、私たちは悪夢を見ちゃう……","ENG":"Without Madam Heron, we’ll have nightmares again...","TWN":"海倫夫人走掉的話我們會做惡夢的……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"악몽은 무서워.","JPN":"悪夢は怖い。","ENG":"Nightmares are scary.","TWN":"惡夢好可怕。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"잠들고 싶지 않아. 악몽 싫어. 무서워. 살려줘…….","JPN":"眠りたくない。悪夢イヤ。怖い。助けて……","ENG":"I don’t want to sleep. No more nightmares... I’m scared... Help me...","TWN":"我不想睡覺，我討厭惡夢，我好怕，救我……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……어쩌지. 이 많은 애들을 다 짊어지고 갈 수도 없고.","JPN":"……どうしよう。この大人数をおんぶして行くわけにもいかないし。","ENG":"What do we do? We can’t carry all the kids with us.","TWN":"……怎麼辦？人這麼多，又不可能全都用揹的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"도로시. 내가 해결할 수 있어.","JPN":"ドロシー。私がなんとかするよ。","ENG":"Dorothy. Leave this to me.","TWN":"桃樂絲，我有辦法。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그 몸으로 뭘 또 어쩌려고 그래!","JPN":"その体でまた何する気なんだよ！","ENG":"What are you gonna do in this state?","TWN":"你又想做什麼！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"너도 알잖아. 내가 뭘 할지.","JPN":"わかるでしょう？　私が何をしようとしてるのか。","ENG":"You already know what I’m going to do.","TWN":"你也知道我想做什麼吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하지만 또 정신을 잃게 되면…… 그보다 이 많은 애들을 무슨 수로 다…….","JPN":"でもまた気を失っちゃうと……それよりこの大人数を全部どうやって……","ENG":"But if you lose consciousness again... More importantly, is it even possible with all these kids...?","TWN":"但是萬一你又暈過去……而且這麼多人，你是要怎麼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다.","JPN":"グリンダ。","ENG":"Glinda.","TWN":"格琳達。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"이건…… 내가 꼭 해야만 하는 일이야.","JPN":"これは……私がやらないといけないことなの。","ENG":"This is... something that I must do.","TWN":"這是……我必須要做的事。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루…….","JPN":"ルル……","ENG":"Lulu...","TWN":"露露……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"잠시만 기다려.","JPN":"ちょっと待ってて。","ENG":"Wait for me.","TWN":"等我一下。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"앗. 애들이…….","JPN":"あっ。みんなが……","ENG":"Huh? The kids...","TWN":"他們……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"하음…… 갑자기…… 졸려…….","JPN":"ふわぁ……急に……眠い……","ENG":"*Yawn...* I’m so... tired...","TWN":"呼哈……突然……好睏……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"눈이 막…… 저절로 감겨…….","JPN":"まぶたが……重い……","ENG":"My eyes... they’re closing on their own...","TWN":"眼皮……好沉……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"걱정 마. 잠시 재운 거니까.","JPN":"心配しないで。しばらく眠らせただけだから。","ENG":"Don’t worry. I just put them to sleep.","TWN":"沒事的，睡一下而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"루루, 아까부터 궁금했는데…… 너도 카운터야?","JPN":"ルルちゃん、さっきから気になってたけど……あなたもカウンターなの？","ENG":"Lulu, I’ve been meaning to ask, but... Are you a Counter?","TWN":"露露，我剛就想問你……你也是制裁者嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응. 카운터…… 그러고 보니 글린다도 그런 얘기를 했지.","JPN":"うん。カウンター……そういえば、グリンダもそんな話をしてたね。","ENG":"Um... Counter...? Come to think of it, Glinda said something similar.","TWN":"嗯，制裁者……這麼說來，格琳達也有這麼說過。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"역시 그랬어!","JPN":"やっぱりそうだったんだ！","ENG":"I knew it!","TWN":"果然沒錯！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"블랙 네트워크에서도 발견하지 못한 처음 보는 능력에, 과학의 법칙에 얽매이지 않는 생소한 패턴!","JPN":"ブラックネットワークでも発見できなかった、初めて見る能力に、科学の法則に縛られない珍しいパターン！","ENG":"There’s no mention of your ability on the Dark Network, and your strange pattern defies scientific laws!","TWN":"沒在黑色網路上出現過的能力，再加上跳脫科學法則的罕見模式！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"뿔이나 눈빛을 보면 확실히 평범한 사람은 아니니까 의심만 하고 있었어.","JPN":"角や目つきを見ると、確かに普通の人間じゃないから疑ってはいたんだよ。","ENG":"I had my suspicions when I saw your horns and your eyes that you weren’t an ordinary person.","TWN":"而且從你頭上的角或眼神，就可以知道你不是普通人，所以我一直懷疑你是不是制裁者呢！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"보통 이쯤이면 냄새가 나거든. 카운터 특유의 냄새랄까? 루루는 그런 게 안 느껴져.","JPN":"普通、このくらいになると匂うもん。カウンター特有の匂いって言うのかな？　ルルちゃんからはそれが感じられなくて。","ENG":"You can almost smell it by then. Like a distinct Counter scent. But I didn’t get that with Lulu.","TWN":"通常這種都會有味道，該說是制裁者特有的味道嗎？但露露沒有。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"냄새로 알아본다고? 너도 토토 닮아가려는 거야?","JPN":"匂いでわかるって？　リオンもトトに似てきた？","ENG":"You can tell by their smell? Are you also trying to become like Toto?","TWN":"靠味道來辨識嗎？你想模仿托托嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"느낌이 그렇다는 거지. 오히려 수아를 닮아가는 게 아닐까?","JPN":"そんな感じだってことだよ。むしろコトリちゃんに似てきてるんじゃないかな？","ENG":"I’m saying that’s how it feels. Maybe I’m becoming more like Skia?","TWN":"就是感覺得出來的意思，比較像是模仿蘇亞吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"음. 확실히. 웬 떠돌이 양이 킁킁거리며 메에하는 기분이야.","JPN":"うん。確かに。迷子の羊がクンクンしながらメェメェしてる気分だ。","ENG":"Hmm. I can see that. She’s like a lost sheep sniffing and crying.","TWN":"嗯，沒錯，就像是一隻流浪羊一邊嗅聞，一邊咩咩叫的感覺。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"바로 그런 거야.","JPN":"そういうこと。","ENG":"That’s exactly it.","TWN":"就是這個意思！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……알다가도 모르겠네.","JPN":"……わかんないなあ。","ENG":"You’re all weird, you know that?","TWN":"……好像懂又好像不懂。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"귀여운 아이들이네.","JPN":"可愛い子たちだね。","ENG":"The kids are all so cute.","TWN":"他們好可愛。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다. 이렇게 많은 사람은 처음이라…… 시간이 조금 걸릴지도 모르겠어.","JPN":"グリンダ。こんなに大勢は初めてで……ちょっと時間がかかるかもしれない。","ENG":"Glinda, I haven’t tried with this many people before... It might take a while.","TWN":"格琳達，這是我第一次面對這麼多人……可能會花上一些時間。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여긴 걱정 말고 다녀와.","JPN":"ここは心配しないで、行ってきな。","ENG":"Don’t worry about us and do your thing.","TWN":"你放心去吧，"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"어떻게든 잘 지키고 있을게.","JPN":"どうにかして守っておくから。","ENG":"We’ll be here protecting you.","TWN":"我在這裡等你回來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 다녀올게, 글린다.","JPN":"うん。行ってくる。","ENG":"Okay. I’ll be back soon, Glinda.","TWN":"嗯，等我回來，格琳達。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};